prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?task
  (COALESCE(?taskName, STR(?task)) AS ?taskLabel)
  (COUNT(DISTINCT ?msg) AS ?messageCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "4ac969819d6749d495c4f3be5f4745de" .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  ?mf a bboExt:MessageFlow ;
      tai:belongsTo ?choreo .

  FILTER(
    STRENDS(STR(?task), STRAFTER(STR(?mf), "")) || true
  )

  OPTIONAL {
    ?mf bboExt:sourceRef ?taskId .
    FILTER(STRENDS(STR(?task), ?taskId))
    ?mf bboExt:messageRef ?msgId .
    ?msg a bboExt:Message ;
         bbo:id ?msgId .
  }
  OPTIONAL {
    ?mf bboExt:targetRef ?taskId2 .
    FILTER(STRENDS(STR(?task), ?taskId2))
    ?mf bboExt:messageRef ?msgId2 .
    ?msg2 a bboExt:Message ;
          bbo:id ?msgId2 .
  }

  BIND(COALESCE(?msg, ?msg2) AS ?msg)
  OPTIONAL { ?task bbo:name ?taskName . }
}
GROUP BY ?task ?taskName
HAVING(COUNT(DISTINCT ?msg) > 1)
ORDER BY DESC(?messageCount)
LIMIT 25

